{\rtf1\ansi\ansicpg0\uc1\deff0\deflang0\deflangfe0{\fonttbl{\f0\fnil\fcharset1 Arial;}{\f1\fnil\fcharset0 Times New Roman;}{\f2\fnil\fcharset2 Symbol;}{\f3\fnil\fcharset0 Courier;}{\f4\fnil\fcharset238 Times New Roman;}{\f5\fnil\fcharset2 Times New Roman;}}{\colortbl;\red0\green0\blue0;\red0\green0\blue255;\red0\green255\blue255;\red0\green255\blue0;\red255\green0\blue255;\red255\green0\blue0;\red255\green255\blue0;\red255\green255\blue255;\red0\green0\blue128;\red0\green128\blue128;\red0\green128\blue0;\red128\green0\blue128;\red128\green0\blue0;\red128\green128\blue0;\red128\green128\blue128;\red192\green192\blue192;\red204\green238\blue221;}

\uc1
\pard\fi0\li0\ql\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs20 Die Handschrift ist zusammengesetzt aus Teilen der urspr\u252 \'fcnglich selbst\u228 \'e4ndigen Handschriften: Erfurt, Kartause Salvatorberg, D 5\plain \f1\super\lang1033\fs20 1\plain \f1\lang1033\fs20  und G 32\plain \f1\super\lang1033\fs20 1\plain \f1\lang1033\fs20 . Aus D 5\plain \f1\super\lang1033\fs20 1\plain \f1\lang1033\fs20  stammen die Faszikel I-III; aus G 32\plain \f1\super\lang1033\fs20 1\plain \f1\lang1033\fs20  stammen Faszikel IV-VII; die Zusammenbindung der nicht zusammengeh\u246 \'f6renden Faszikel erfolgte erstmals wohl im 1. Drittel des 19. Jh.s, s. u. Eintrag im \plain \f1\scaps\lang1033\fs20 Preller\plain \f1\lang1033\fs20 -Katalog  \u183 \'b7  bei der neuzeitlichen Bleistiftfoliierung (20. Jh.?) wurden ein Bl. nach Bl. 259 (Bl. 259a) und ein kleiner Schaltzettel nach Bl. 161 (Bl. 161a) \u252 \'fcbersprungen; die vielen eingef\u252 \'fcgten Bl\u228 \'e4tter und Schaltzettel wurden sonst mitgez\u228 \'e4hlt  \u183 \'b7  Blattweiser aus rotgef\u228 \'e4rbtem Leder (?), z. T. ausgerissen.
\par \pard\fi0\li0\ql\ri0\sb0\sa0\itap0 \par}

