\pard\fi0\li0\qj\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs24 (63\plain \f1\super\lang1033\fs24 r\plain \f1\lang1033\fs24 -64\plain \f1\super\lang1033\fs24 v\plain \f1\lang1033\fs24 , 67\plain \f1\super\lang1033\fs24 r\plain \f1\lang1033\fs24 -68\plain \f1\super\lang1033\fs24 r\plain \f1\lang1033\fs24 )\plain \f1\b\lang1033\fs24  Exzerptsammlung Teil IV: {\field{\*\fldinst HYPERLINK "hida://bezwrk[0].6930/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 Biblia}}\plain \f1\b\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezper[0].4100/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 Petrus Comestor}}\plain \f1\b\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezper[1].4100/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 Augustinus}}\plain \f1\b\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezper[2].4100/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 Hieronymus}}\plain \f1\b\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[2].6930/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 Glossa ordinaria}}\plain \f1\b\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezper[3].4100/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 Johannes de Indagine}}\plain \f1\b\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezper[4].4100/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 Vincentius Bellovacensis}}\plain \f1\b\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezper[5].4100/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 John Mandeville}}\plain \f1\b\lang1033\fs24  etc.
\par \pard\fi0\li0\qj\ri0\sb0\sa0\itap0 \plain \f1\i\lang1033\fs24 Item in Apocalypsi xx\u176 \'b0 capitulo: Et cum consummati fuerint mille anni \u8230 \'85 \plain \f1\lang1033\fs24 (Apc 20,7-9); \plain \f1\i\lang1033\fs24 Et hec est prophetatum in Ezechiele capitulo xxxviii ubi sic habetur: Et fili hominis pone faciem tuam contra Gog \plain \f2\lang1024\fs24 [\plain \f1\lang1033\fs24 marginal eingef\u252 \'fcgt: \plain \f1\i\lang1033\fs24 terram\plain \f2\lang1024\fs24 ]\plain \f1\lang1033\fs24  \plain \f1\i\lang1033\fs24 Magog ...\plain \f1\lang1033\fs24  (Ez 38,2-6); (a) \plain \f1\i\lang1033\fs24 Josephus dicit \plain \f2\lang1024\fs24 [\plain \f1\lang1033\fs24 drei Worte gestrichen\plain \f2\lang1024\fs24 ]\plain \f1\i\lang1033\fs24 :\plain \f1\lang1033\fs24  \plain \f1\i\lang1033\fs24 filii Japhet tenuerunt septentrionalem regionem \u8230 \'85\plain \f1\lang1033\fs24 ; (b) \plain \f1\i\lang1033\fs24 Item super illo uerbo dicunt aliqui doctores, Lira et alii expositores, quod Gog debet intellegi antichristus eciam opinio Augustini et Ieronimi \u8230 \'85 \plain \f1\lang1033\fs24 (63\plain \f1\super\lang1033\fs24 v\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 \u8230 \'85 ut patet per Augustinum De ciuitate dei capitulo xi et per beatum Ieronimum super Ezechielem capitulo xi \u8230 \'85\plain \f1\lang1033\fs24 ; (c) \plain \f1\i\lang1033\fs24 Glossa ordinaria autem super Apocalypsem \u8230 \'85\plain \f1\lang1033\fs24 ; (d) \plain \f1\i\lang1033\fs24 Indaginis circa capitulum 38 super Ezechielem scilicet in questionibus super Ezechielem dicit: \u8230 \'85\plain \f1\lang1033\fs24 ; (64\plain \f1\super\lang1033\fs24 r\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 \u8230 \'85 \plain \f1\lang1033\fs24 (e) \plain \f1\i\lang1033\fs24 De quibus Tartaris in ultimo libro Speculi historialis et in itinerario magistri Iohannis de Mandeuelde plura habentur: Tartarorum imperium et imperator dicitur Grancan\plain \f1\lang1033\fs24  \plain \f2\lang1024\fs24 [\plain \f1\lang1033\fs24 lies: Grand Can\plain \f2\lang1024\fs24 ]\plain \f1\i\lang1033\fs24  \u8230 \'85\plain \f1\lang1033\fs24 ;\plain \f1\i\lang1033\fs24  \plain \f1\lang1033\fs24 (f) \plain \f1\i\lang1033\fs24 Totum imperium imperatoris Grand Can distinctum est in xxii magnas prouincias ... Imperator Tartarie et imperator Indie: Istis duobus imperatoribus non creditur inueniri maior dominus sub celi firmamento ...\plain \f1\lang1033\fs24 ;\plain \f1\i\lang1033\fs24  \plain \f1\lang1033\fs24 (g) \plain \f1\i\lang1033\fs24 \u8230 \'85 habetur in ultimo libri Speculi historialis et penultimo libro eiusdem Speculi capitulo cxl et capitulo cxlv: Item anno domini M cc xlii Thartari vastaverunt Poloniam et Vngariam ... \plain \f2\lang1024\fs24 [\plain \f1\lang1033\fs24 eingeschaltetes Doppelblatt 65/66 s. u., vgl. Notiz am unteren Rand von 64\plain \f1\super\lang1033\fs24 v\plain \f1\lang1033\fs24 : \plain \f1\i\lang1033\fs24 post ista duo folia extranea habes continuacionem\plain \f2\lang1024\fs24 ]\plain \f1\lang1033\fs24  \plain \f1\i\lang1033\fs24 ...\plain \f1\lang1033\fs24  \plain \f1\i\lang1033\fs24 - \u8230 \'85 \plain \f1\lang1033\fs24 (68\plain \f1\super\lang1033\fs24 r\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 \u8230 \'85 qui fuit imperator effectus anno M cc xlvi. Hic omnia ex ultimo libro Speculi hystoriali.
\par \pard\fi0\li0\ql\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs24 Exzerpte u. a. aus: (a) \plain \f1\scaps\lang1033\fs24 Petrus Comestor\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[3].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Historia scholastica}}\plain \f1\lang1033\fs24 , cap. 37, vgl. PL 198, Sp. 1087D; (b) \plain \f1\scaps\lang1033\fs24 Augustinus\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[4].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 De civitate dei}}\plain \f1\lang1033\fs24 , cap. 9, \plain \f1\scaps\lang1033\fs24 Hieronymus\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[5].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Super Ezechielem}}\plain \f1\lang1033\fs24 , cap. 11; (c) Glossa ordinaria; (d) \plain \f1\scaps\lang1033\fs24 Johannes de Indagine\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[6].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Super Ezechielem expositio}}\plain \f1\lang1033\fs24 , vgl. \plain \f1\scaps\lang1033\fs24 Klapper\plain \f1\lang1033\fs24  I, S. 80; II, S. 14, 16; zur \u220 \'dcberlieferung des Ezechiel-Kommentars des \plain \f1\scaps\lang1033\fs24 Johannes de Indagine\plain \f1\lang1033\fs24  in Hss. der Erfurter Kartause vgl. MBK II, Reg. S. 724f.; (e, g) \plain \f1\scaps\lang1033\fs24 Vincentius Bellovacensis\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[7].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Speculum historiale}}\plain \f1\lang1033\fs24 , pars IV, lib. 31, cap. 140, 145, vgl. Druck: [Strassburg]: Johann Mentelin, 4.XII.1473, GW M50587 (eingesehenes Digitalisat M\u252 \'fcnchen, BSB, 2 Inc. c. a. 236,4-3/4: http://daten.digitale-sammlungen.de/~db/0003/bsb00035802/images/ [Stand 12.11.09]); (f) \plain \f1\scaps\lang1033\fs24 John Mandeville\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[8].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Itinerarium}}\plain \f1\lang1033\fs24 , cap. 38, 37, Edition und Literatur s. o. 57\plain \f1\super\lang1033\fs24 v\plain \f1\lang1033\fs24 .}

