\pard\fi0\li0\qj\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs24 (65\plain \f1\super\lang1033\fs24 r\plain \f1\lang1033\fs24 -66\plain \f1\super\lang1033\fs24 v\plain \f1\lang1033\fs24 ) [eingeschaltetes Doppelbl.] \plain \f1\b\lang1033\fs24 Exzerpte \u252 \'fcber die {\field{\*\fldinst HYPERLINK "hida://bezwrk[0].6930/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 Urspr\u252 \'fcnge der Goten, Vandalen, Hunnen und Slawen}}\plain \f1\b\lang1033\fs24 : {\field{\*\fldinst HYPERLINK "hida://bezper[0].4100/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 Jacobus Philippus Foresti}}\plain \f1\b\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezper[1].4100/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 Vincentius Bellovacensis}}\plain \f1\b\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezper[2].4100/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 Dietrich Engelhus}}\plain \f1\b\lang1033\fs24  etc.
\par \pard\fi0\li0\qj\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs24 (a) \plain \f1\i\lang1033\fs24 Primus filius \plain \f1\i\strike\lang1033\fs24 Noe\plain \f1\i\lang1033\fs24  \plain \f1\lang1033\fs24 [dar\u252 \'fcber vom Schreiber eingef\u252 \'fcgt: \plain \f1\i\lang1033\fs24 Japhet\plain \f1\lang1033\fs24 ] \plain \f1\i\lang1033\fs24 fuit Gomer ...\plain \f1\lang1033\fs24 ; (b) \plain \f1\i\lang1033\fs24 In Supplementum cronicarum libro nono folio 168: Gothia aut regio Europe superioris pars est ...\plain \f1\lang1033\fs24 ; (c) \plain \f1\i\lang1033\fs24 Hermaricus Gotharum rex Geberico patre sublato regnum ...\plain \f1\lang1033\fs24 ; (65\plain \f1\super\lang1033\fs24 v\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 ... \plain \f1\lang1033\fs24 (d) \plain \f1\i\lang1033\fs24 In tercia parte Speculi historialis libro xvii capitulo xiii habetur de origine regni Wandalorum ...\plain \f1\lang1033\fs24 ;\plain \f1\i\lang1033\fs24  \plain \f1\lang1033\fs24 (e) \plain \f1\i\lang1033\fs24 De origine regni Gothorum ...\plain \f1\lang1033\fs24 ; (66\plain \f1\super\lang1033\fs24 r\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 ... \plain \f1\lang1033\fs24 (f) \plain \f1\i\lang1033\fs24 De ortu regni Hunnorum ...\plain \f1\lang1033\fs24 ; (66\plain \f1\super\lang1033\fs24 v\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 ... \plain \f1\lang1033\fs24 (g) \plain \f1\i\lang1033\fs24 Ex cronica Engelhussen de quatuor gentibus: Quatuor gentes Scythie, scilicet Gothi, Ypogoti, Gyppedes \plain \f1\lang1033\fs24 (?)\plain \f1\i\lang1033\fs24  et Wandali siue Slaui unam lingwam habentes ...\plain \f1\lang1033\fs24  \plain \f1\i\lang1033\fs24 - \u8230 \'85 numero 120 sua subiecit dicioni.
\par \pard\fi0\li0\ql\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs24 (b)\plain \f1\scaps\lang1033\fs24  Jacobus Philippus Foresti\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[1].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Supplementum Chronicarum}}\plain \f1\lang1033\fs24 , lib. IX, zur Hs. G 24 der Erfurter Kartause s. o. 54\plain \f1\super\lang1033\fs24 v\plain \f1\lang1033\fs24 ; (d, h) \plain \f1\scaps\lang1033\fs24 Vincentius Bellovacensis\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[2].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Speculum historiale}}\plain \f1\lang1033\fs24 ; (g) \plain \f1\scaps\lang1033\fs24 Dietrich Engelhus\plain \f1\lang1033\fs24 , lat Chronik (,{\field{\*\fldinst HYPERLINK "hida://bezwrk[3].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Weltchronik\rquote }}\plain \f1\lang1033\fs24 ?), vgl. D. \plain \f1\scaps\lang1033\fs24 Berg\plain \f1\lang1033\fs24 , in: \plain \f1\super\lang1033\fs24 2\plain \f1\lang1033\fs24 VL 2 (1980), Sp. 556f.; V. \plain \f1\scaps\lang1033\fs24 Honemann\plain \f1\lang1033\fs24  (Hg.), Dietrich Engelhus, Beitr\u228 \'e4ge zu Leben und Werk, K\u246 \'f6ln, Weimar, Wien 1991 (Mitteldeutsche Forschungen 104).}

