\pard\fi0\li0\qj\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs24 123\plain \f1\super\lang1033\fs24 r\plain \f1\lang1033\fs24  \plain \f1\b\lang1033\fs24 Liste empfohlener B\u252 \'fccher zur {\field{\*\fldinst HYPERLINK "hida://bezwrk[0].6930/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 Astrologie}}\plain \f1\lang1033\fs24 .
\par \pard\fi0\li0\qj\ri0\sb0\sa0\itap0 \plain \f1\i\lang1033\fs24 Si quis uult scire aut legere de astrologia scilicet quomodo admittitur a doctoribus et quomodo non admittitur perlegat libros et loca infra notatos: ...
\par \pard\fi0\li0\ql\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs24 Z. T. mit Hinweis auf die entsprechenden Signaturen der Bibliothek der Erfurter Kartause, u. a. {\field{\*\fldinst HYPERLINK "hida://bezper[0].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Thomas de Aquino}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[1].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 De iudiciis astrorum}}\plain \f1\lang1033\fs24  (\plain \f1\i\lang1033\fs24 in libraria sub littera E vii\plain \f1\lang1033\fs24 , vgl. MBK II, S. 328\plain \f1\super\lang1033\fs24 21\plain \f1\lang1033\fs24 ), {\field{\*\fldinst HYPERLINK "hida://bezper[1].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Antoninus Florentinus}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[2].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Summa theologica}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezper[2].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Johannes Gerson}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[3].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 De astrologia theologisate}}\plain \f1\lang1033\fs24  und {\field{\*\fldinst HYPERLINK "hida://bezwrk[4].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 De observatione dierum}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezper[3].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Augustinus}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[5].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 De civitate dei}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezper[4].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Eusebius Caesarienis}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[6].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 De evangelica praeparatione}}\plain \f1\lang1033\fs24  (\plain \f1\i\lang1033\fs24 sub littera H 77\plain \f1\lang1033\fs24 , vgl. MBK II, S. 409\plain \f1\super\lang1033\fs24 38\plain \f1\lang1033\fs24 , 526\plain \f1\super\lang1033\fs24 25f.\plain \f1\lang1033\fs24 ), {\field{\*\fldinst HYPERLINK "hida://bezper[5].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Vincentius Bellovacensis}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[7].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Speculum doctrinale}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezper[6].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Bartholomaeus Anglicus}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[8].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 De propietatibus rerum}}\plain \f1\lang1033\fs24  (Hs. N 2, vgl. MBK II, S. 481). Daran: \plain \f1\i\lang1033\fs24 Nota: Sciendum est quod in libris tam impressis quam scriptis sepissime reperitur diuersitas et confusio inter duobus dicionibus scilicet astronomia et astrologia ...\plain \f1\lang1033\fs24 , der Schreiber empfiehlt zur genaueren Unterscheidung die {\field{\*\fldinst HYPERLINK "hida://bezwrk[9].6930/?u"}{\fldrslt \plain \f1\i\lang1033\fs24\chcbpat17 tabula super libros Nicolai de Lyra}}\plain \f1\lang1033\fs24  sowie das Speculum doctrinale des {\field{\*\fldinst HYPERLINK "hida://bezper[5].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Vincentius Bellovacensis}}\plain \f1\lang1033\fs24 . }

