\pard\fi0\li0\qj\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs24 123\plain \f1\super\lang1033\fs24 v\plain \f1\lang1033\fs24  {\field{\*\fldinst HYPERLINK "hida://bezwrk[0].6930/?u"}{\fldrslt \plain \f1\b\lang1033\fs24\chcbpat17 Quaestio an Abraham fuit astrologus}}\plain \f1\b\lang1033\fs24 ?\plain \f1\lang1033\fs24  
\par \pard\fi0\li0\qj\ri0\sb0\sa0\itap0 \plain \f1\i\lang1033\fs24 Item in libro octauo Eusebii Cesariensis de preparacione evangelica \plain \f1\lang1033\fs24 (s. o. 123\plain \f1\super\lang1033\fs24 r\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 habetur de Abraham quomodo in Egyptum profectum ... \plain \f1\lang1033\fs24 - \plain \f1\i\lang1033\fs24 ... cepi dubitare an Abraham etc. fuit astrologus an non ... Et superius tactus est quod Abraham docuit eos astrologiam. Ergo adhuc dubium meum manet.\plain \f1\lang1033\fs24  
\par \pard\fi0\li0\ql\ri0\sb0\sa0\itap0 Exzerpt aus {\field{\*\fldinst HYPERLINK "hida://bezper[0].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Eusebius Caesariensis}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[1].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 De praeparatione evangelica}}\plain \f1\lang1033\fs24 , lib. 8, sowie Kommentar des Schreibers, dabei Auseinandersetzung mit den Aussagen des j\u252 \'fcdischen Historikers {\field{\*\fldinst HYPERLINK "hida://bezper[1].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Artapanus}}\plain \f1\lang1033\fs24  (in \plain \f1\scaps\lang1033\fs24 Eusebius\plain \f1\lang1033\fs24 , De praeparatione evangelica \u252 \'fcberliefert), des {\field{\*\fldinst HYPERLINK "hida://bezper[2].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Flavius Josephus}}\plain \f1\lang1033\fs24  sowie der {\field{\*\fldinst HYPERLINK "hida://bezwrk[2].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Postilla}}\plain \f1\lang1033\fs24  des {\field{\*\fldinst HYPERLINK "hida://bezper[3].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Nicolaus de Lyra}}\plain \f1\lang1033\fs24 .}

