\par \pard\fi0\li0\qj\ri0\sb0\sa0\itap0 (a) \plain \f1\i\lang1033\fs24 Nota in Supplementum cronic\plain \f2\lang1024\fs24 [\plain \f1\lang1033\fs24 arum? \u8230 \'85, Textverlust\plain \f2\lang1024\fs24 ]\plain \f1\lang1033\fs24  \plain \f1\i\lang1033\fs24 in paradiso xxix annis \plain \f2\lang1024\fs24 [\plain \f1\lang1033\fs24 Textverlust\plain \f2\lang1024\fs24 ]\plain \f1\lang1033\fs24  \plain \f1\i\lang1033\fs24 et expulsum \plain \f1\lang1033\fs24 ...;\plain \f1\i\lang1033\fs24  \plain \f1\lang1033\fs24 (b) \plain \f1\i\lang1033\fs24 Isidorus 5\u176 \'b0 et\plain \f2\lang1024\fs24 [\plain \f1\lang1033\fs24 imolog\plain \f2\lang1024\fs24 ]\plain \f1\i\lang1033\fs24 iarum dicit: Adam \plain \f2\lang1024\fs24 [\plain \f1\lang1033\fs24 anno\plain \f2\lang1024\fs24 ]\plain \f1\lang1033\fs24  \plain \f1\i\lang1033\fs24 230 genuit Seth \u8230 \'85\plain \f1\lang1033\fs24 ;\plain \f1\i\lang1033\fs24  \plain \f1\lang1033\fs24 (c) \plain \f1\i\lang1033\fs24 Europe prima regio est Scitia inferior, que Barbarica dicitur ... Alania, Dacia, Gothia, Germania ... \plain \f1\lang1033\fs24 ; (259\plain \f1\super\lang1033\fs24 v\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 \u8230 \'85 \plain \f1\lang1033\fs24 (d) \plain \f1\i\lang1033\fs24 Ouidius Naso dampnatus in exilium ab Augusto \u8230 \'85 scribit in libro de vetula \plain \f1\lang1033\fs24 \u8230 \'85\plain \f1\i\lang1033\fs24 :\plain \f1\lang1033\fs24  \plain \f1\i\lang1033\fs24 O virgo felix, o virgo significata per stellas ...\plain \f1\lang1033\fs24 ;\plain \f1\i\lang1033\fs24  \plain \f1\lang1033\fs24 (259a\plain \f1\super\lang1033\fs24 v\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 \u8230 \'85\plain \f1\lang1033\fs24  (e) \plain \f2\lang1024\fs24 [\plain \f1\lang1033\fs24 Notizen zu Kaiser Albrecht II. (1397-1439)\plain \f2\lang1024\fs24 ]\plain \f1\lang1033\fs24  \plain \f1\i\lang1033\fs24 Albertus dux Austrie fuit imperator \u8230 \'85 pugnauit contra regem Turchorum \u8230 \'85\plain \f1\lang1033\fs24 ;\plain \f1\i\lang1033\fs24  \plain \f1\lang1033\fs24 (f) \plain \f2\lang1024\fs24 [\plain \f1\lang1033\fs24 Notizen zum Gegenpapst Johannes XXXIII., \u8224 \'86 1419\plain \f2\lang1024\fs24 ]\plain \f1\i\lang1033\fs24  Jo\plain \f2\lang1024\fs24 [\plain \f1\lang1033\fs24 hannes\plain \f2\lang1024\fs24 ]\plain \f1\lang1033\fs24  \plain \f1\i\lang1033\fs24 xxiii electus in concilio Pisano \u8230 \'85\plain \f1\lang1033\fs24 ; (f) \plain \f1\i\lang1033\fs24 Concilium Constantiniense durauit\plain \f1\lang1033\fs24  (?) \plain \f1\i\lang1033\fs24 in omni libertate ... ad concilium Basiliense ... 
\par \pard\fi0\li0\ql\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs24 Exzerpte u. a. aus (a) {\field{\*\fldinst HYPERLINK "hida://bezper[0].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Jacobus Philippus Foresti}}\plain \f1\lang1033\fs24 : {\field{\*\fldinst HYPERLINK "hida://bezwrk[1].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Supplementum chronicarum}}\plain \f1\lang1033\fs24  (s. o. 54\plain \f1\super\lang1033\fs24 r\plain \f1\lang1033\fs24 ); (b) {\field{\*\fldinst HYPERLINK "hida://bezper[1].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Isidorus Hispalensis}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[2].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 Etymologiae}}\plain \f1\lang1033\fs24  V,39,2; (c) ebd., XIV,4,3; (d) {\field{\*\fldinst HYPERLINK "hida://bezper[2].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Ps.-Ovidius}}\plain \f1\lang1033\fs24 , {\field{\*\fldinst HYPERLINK "hida://bezwrk[3].6930/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 De vetula}}\plain \f1\lang1033\fs24 , lib. III, v. 772-776, vgl. Edition: P. \plain \f1\scaps\lang1033\fs24 Klopsch\plain \f1\lang1033\fs24 , Pseudo-Ovidius de Vetula. Untersuchung und Text, Leiden, K\u246 \'f6ln 1967 (Mittelalterliche Studien und Texte 2), S. 277.}

